const FURRY_INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"zh-CN\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>FurryOC 形象提示词生成器 | Sewindwolf</title>\n  <link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n  <link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n  <link href=\"https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;500;700;900&display=swap\" rel=\"stylesheet\">\n  <link rel=\"stylesheet\" href=\"style.css?v=20260519-extra-detail-output\" />\n</head>\n<body>\r\n  <script>window.APP_VERSION = '20260519-extra-detail-output';</script>\n  <div class=\"shell\">\n    <header class=\"hero\">\n      <div class=\"badge\">SEWINDWOLF · CHARACTER LAB</div>\n      <h1>FurryOC形象提示词生成</h1>\n      <p>通过少量选择快速生成 Furry OC 设定、Nano Banana Pro 可用英文提示词、负面提示词与 JSON 数据。输入授权密码后，可提交 Banana 生图任务并查看生成结果。</p>\n      <div class=\"hero-actions\">\n        <button class=\"primary\" id=\"startWizardBtn\">开始填写</button>\n        <button class=\"ghost\" id=\"randomAllBtn\">完全随机一个惊喜</button>\n        <button class=\"ghost\" id=\"resetBtn\">重新填写</button>\n        <button class=\"ghost\" id=\"refreshLatestBtn\" type=\"button\">刷新到最新版</button>\n      </div>\n    </header>\n\n    <main class=\"grid\">\n      <section class=\"panel form-panel\">\n        <div class=\"panel-title\">\n          <span>01</span>\n          <h2>分步问卷</h2>\n        </div>\n        <div id=\"questions\" class=\"questions\"></div>\n        <div class=\"advanced\" id=\"advancedBox\">\n          <h3>05 可选细节 / 微调项</h3>\n          <p class=\"advanced-note\">这些选项用于最后微调自动补全。随机强度会影响系统自动补全和“完全随机一个惊喜”的变化幅度；混沌随机会更大胆，但仍会尽量保持角色设定可用。</p>\n          <div class=\"advanced-grid\">\n            <label>花纹复杂度\n              <select id=\"markingComplexity\">\n                <option value=\"auto\">系统推荐</option>\n                <option value=\"clean\">简单干净</option>\n                <option value=\"natural\">少量自然花纹</option>\n                <option value=\"distinct\">明显动物花纹</option>\n                <option value=\"ornate\">华丽图案</option>\n                <option value=\"glowing\">发光纹路</option>\n              </select>\n            </label>\n            <label>体型\n              <select id=\"bodyType\">\n                <option value=\"auto\">系统推荐</option>\n                <option value=\"slim\">修长</option>\n                <option value=\"athletic\">运动型</option>\n                <option value=\"soft\">柔和圆润</option>\n                <option value=\"strong\">强壮</option>\n                <option value=\"tall\">高挑</option>\n              </select>\n            </label>\n            <label>随机强度\n              <select id=\"randomnessLevel\">\n                <option value=\"safe\">保守随机</option>\n                <option value=\"moderate\" selected>中度随机</option>\n                <option value=\"bold\">大胆随机</option>\n                <option value=\"chaos\">混沌随机</option>\n              </select>\n            </label>\n          </div>\n        </div>\n        <button class=\"generate\" id=\"generateBtn\">生成结果</button>\n      </section>\n\n      <section class=\"panel result-panel\">\n        <div class=\"panel-title\">\n          <span>02</span>\n          <h2>生成结果</h2>\n        </div>\n        <div class=\"summary-card\">\n          <h3>形象摘要</h3>\n          <p id=\"summary\">请按步骤完成问卷，系统会在最后生成结果。</p>\n          <div class=\"tags\" id=\"tags\"></div>\n          <div class=\"reroll-row\">\n            <button data-reroll=\"species\">重随机物种</button>\n            <button data-reroll=\"color\">重随机配色</button>\n            <button data-reroll=\"outfit\">重随机服装</button>\n          </div>\n          <div class=\"manual-result-panel\">\n            <div class=\"manual-result-title\">对结果不满意？手动替换局部设定（每项最多30字）</div>\n            <div class=\"manual-result-grid\">\n              <label>物种<input id=\"manualSpeciesInput\" maxlength=\"12\" placeholder=\"如：金毛寻回犬\" /></label>\n              <label>配色<input id=\"manualColorInput\" maxlength=\"12\" placeholder=\"如：金黄色\" /></label>\n              <label>服装<input id=\"manualOutfitInput\" maxlength=\"12\" placeholder=\"如：学院披肩\" /></label>\n              <label>额外细节<input id=\"manualHeadInput\" maxlength=\"30\" placeholder=\"如：单尖耳\" /></label>\n            </div>\n            <div class=\"manual-result-actions\">\n              <button data-manual=\"species\">替换物种</button>\n              <button data-manual=\"color\">替换配色</button>\n              <button data-manual=\"outfit\">替换服装</button>\n              <button data-manual=\"head\">替换额外细节</button>\n            </div>\n          </div>\n        </div>\n\n        <div class=\"tabs\">\n          <button class=\"tab active\" data-tab=\"description\">形象文字描述</button><button class=\"tab\" data-tab=\"banana\">Banana 可用提示词</button>\n          <button class=\"tab\" data-tab=\"negative\">负面提示词</button>\n          <button class=\"tab\" data-tab=\"json\">JSON 数据</button>\n        </div>\n        <textarea id=\"output\" spellcheck=\"false\" readonly></textarea>\n        <div class=\"copy-row\">\n          <button class=\"primary\" id=\"copyBtn\">复制当前内容</button>\n          <button class=\"ghost\" id=\"downloadBtn\">下载 JSON</button>\n          <button class=\"banana-action\" id=\"bananaGenerateBtn\">提交 Banana 生图任务</button>\n          <button class=\"gpt-action\" id=\"gptGenerateBtn\" type=\"button\">GPT</button>\n        </div>\n        <div class=\"banana-box\" id=\"bananaBox\" hidden>\n          <div class=\"banana-password-panel\" id=\"bananaPasswordPanel\">\n            <label>生图密码\n              <input id=\"bananaPasswordInput\" type=\"password\" autocomplete=\"current-password\" inputmode=\"text\" placeholder=\"在这里输入密码\" />\n            </label>\n            <div class=\"banana-password-actions\">\n              <button class=\"primary\" id=\"bananaPasswordSubmitBtn\">提交生图</button>\n              <button class=\"ghost\" id=\"bananaPasswordCancelBtn\">取消</button>\n            </div>\n            <p class=\"custom-note\">安卓端如果不弹出系统密码框，可以直接在这里输入密码。</p>\n          </div>\n          <div class=\"banana-status\" id=\"bananaStatus\">等待提交</div>\n          <div class=\"banana-preview\" id=\"bananaPreview\"></div>\n        </div>\n        <p class=\"note\">说明：点击“提交 Banana 生图任务”或“GPT”后会在页面内显示密码输入框，密码正确才会用当前提示词提交对应生图任务；生成完成后会显示图片预览和原图链接。</p>\n        <div class=\"version-row\">当前版本：<span id=\"versionText\">20260519-extra-detail-output</span></div>\r\n      </section>\r\n    </main>\n  </div>\n  <script>\r\n    document.getElementById('versionText') && (document.getElementById('versionText').textContent = window.APP_VERSION || '20260519-extra-detail-output');\r\n    document.getElementById('refreshLatestBtn') && document.getElementById('refreshLatestBtn').addEventListener('click', function(){\r\n      location.replace('/furry-creator/?v=' + Date.now());\r\n    });\r\n  </script>\r\n  <script src=\"app.js?v=20260519-extra-detail-output\"></script>\n</body>\n</html>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n";
const FURRY_STYLE_CSS = ":root {\n  --bg: #10131f;\n  --card: rgba(255,255,255,.08);\n  --card-strong: rgba(255,255,255,.13);\n  --line: rgba(255,255,255,.16);\n  --text: #f5f7ff;\n  --muted: #abb4d2;\n  --accent: #8fd3ff;\n  --accent2: #ffd28f;\n  --good: #9ef0c2;\n  --shadow: 0 24px 70px rgba(0,0,0,.35);\n}\n* { box-sizing: border-box; }\nbody {\n  margin: 0;\n  min-height: 100vh;\n  font-family: 'Noto Sans SC', system-ui, sans-serif;\n  color: var(--text);\n  background:\n    radial-gradient(circle at 12% 10%, rgba(143,211,255,.28), transparent 30%),\n    radial-gradient(circle at 85% 15%, rgba(255,210,143,.22), transparent 28%),\n    linear-gradient(135deg, #0c1020, #151a2a 58%, #21172a);\n}\nbutton, select { font: inherit; }\n.shell { width: min(1260px, calc(100% - 32px)); margin: 0 auto; padding: 32px 0 48px; }\n.hero {\n  padding: 42px;\n  border: 1px solid var(--line);\n  background: linear-gradient(135deg, rgba(255,255,255,.12), rgba(255,255,255,.04));\n  border-radius: 32px;\n  box-shadow: var(--shadow);\n  overflow: hidden;\n  position: relative;\n}\n.hero:after {\n  content: '';\n  position: absolute;\n  width: 360px;\n  height: 360px;\n  border-radius: 50%;\n  right: -120px;\n  top: -150px;\n  background: radial-gradient(circle, rgba(143,211,255,.35), transparent 64%);\n}\n.badge { color: var(--accent2); font-weight: 900; letter-spacing: .16em; font-size: 13px; }\nh1 { margin: 12px 0 10px; font-size: clamp(34px, 6vw, 68px); line-height: 1; }\n.hero p { max-width: 760px; color: var(--muted); font-size: 18px; line-height: 1.8; }\n.hero-actions, .copy-row, .reroll-row { display: flex; gap: 12px; flex-wrap: wrap; }\nbutton {\n  border: 1px solid var(--line);\n  border-radius: 999px;\n  color: var(--text);\n  background: rgba(255,255,255,.08);\n  padding: 10px 16px;\n  cursor: pointer;\n  transition: .2s ease;\n}\nbutton:hover { transform: translateY(-1px); border-color: rgba(143,211,255,.62); background: rgba(143,211,255,.12); }\n.primary, .generate { color: #08111c; background: linear-gradient(135deg, var(--accent), var(--accent2)); border: none; font-weight: 900; }\n.ghost { background: rgba(255,255,255,.04); }\n.grid { display: grid; grid-template-columns: .95fr 1.05fr; gap: 22px; margin-top: 22px; align-items: start; }\n.panel {\n  border: 1px solid var(--line);\n  background: rgba(15,19,34,.76);\n  backdrop-filter: blur(16px);\n  border-radius: 28px;\n  padding: 24px;\n  box-shadow: var(--shadow);\n}\n.panel-title { display: flex; align-items: center; gap: 14px; margin-bottom: 18px; }\n.panel-title span { width: 42px; height: 42px; display: grid; place-items: center; border-radius: 14px; background: var(--card-strong); color: var(--accent2); font-weight: 900; }\n.panel-title h2 { margin: 0; font-size: 24px; }\n.questions { display: grid; gap: 18px; }\n.question { padding: 16px; border: 1px solid var(--line); border-radius: 20px; background: rgba(255,255,255,.045); }\n.question h3 { margin: 0 0 12px; font-size: 16px; }\n.options { display: flex; flex-wrap: wrap; gap: 9px; }\n.option { padding: 9px 13px; border-radius: 999px; font-size: 14px; }\n.option.active, .tag.locked { background: rgba(143,211,255,.22); border-color: var(--accent); color: #dff4ff; }\n.advanced { margin-top: 18px; padding: 16px; border-radius: 20px; border: 1px dashed rgba(255,255,255,.22); }\n.advanced h3, .summary-card h3 { margin: 0 0 12px; }\n.advanced-grid { display: grid; gap: 12px; }\nlabel { display: grid; gap: 7px; color: var(--muted); font-size: 14px; }\nselect {\n  width: 100%;\n  padding: 10px 12px;\n  color: var(--text);\n  background: #171d31;\n  border: 1px solid var(--line);\n  border-radius: 12px;\n}\n.generate { width: 100%; margin-top: 18px; border-radius: 18px; padding: 14px; font-size: 16px; }\n.summary-card { padding: 18px; border-radius: 22px; background: linear-gradient(135deg, rgba(143,211,255,.12), rgba(255,210,143,.08)); border: 1px solid var(--line); }\n#summary { color: #e7ecff; line-height: 1.8; }\n.tags { display: flex; flex-wrap: wrap; gap: 9px; margin: 14px 0; }\n.tag { border-radius: 999px; padding: 8px 11px; background: rgba(255,255,255,.08); border: 1px solid var(--line); font-size: 13px; user-select: none; }\n.tag:before { content: '锁定 '; color: var(--muted); }\n.tag.locked:before { content: '已锁 '; color: var(--good); }\n.tabs { margin-top: 18px; display: flex; gap: 8px; flex-wrap: wrap; }\n.tab.active { background: var(--card-strong); border-color: var(--accent); }\ntextarea {\n  width: 100%;\n  min-height: 390px;\n  margin-top: 12px;\n  resize: vertical;\n  border: 1px solid var(--line);\n  border-radius: 20px;\n  padding: 16px;\n  color: #eef3ff;\n  background: rgba(5,8,16,.72);\n  line-height: 1.62;\n  font-family: Consolas, 'Noto Sans SC', monospace;\n}\n.copy-row { margin-top: 12px; }\n.note { color: var(--muted); line-height: 1.7; font-size: 13px; }\n@media (max-width: 920px) {\n  .grid { grid-template-columns: 1fr; }\n  .hero { padding: 28px; }\n}\r\n.grid{grid-template-columns:1fr;max-width:940px;margin-left:auto;margin-right:auto}.form-panel,.result-panel{min-height:560px}.step-meta{display:flex;align-items:center;justify-content:space-between;gap:14px;margin-bottom:18px;color:var(--muted);font-size:14px}.step-bar{height:9px;border-radius:999px;background:rgba(255,255,255,.1);overflow:hidden;flex:1}.step-bar i{display:block;height:100%;border-radius:999px;background:linear-gradient(135deg,var(--accent),var(--accent2))}.wizard-question{min-height:260px;display:grid;align-content:center}.wizard-question h3{font-size:clamp(24px,4vw,38px);line-height:1.25;margin-bottom:10px}.wizard-tip{color:var(--muted);line-height:1.8;margin:0 0 22px}.wizard-nav{display:flex;justify-content:space-between;gap:12px;flex-wrap:wrap;margin-top:22px}.wizard-nav .right{margin-left:auto}.result-panel{display:none}.option{font-size:15px;padding:11px 16px}.advanced{display:block}.step-fade{animation:stepFade .22s ease}@keyframes stepFade{from{opacity:.25;transform:translateY(8px)}to{opacity:1;transform:none}}@media(max-width:700px){.wizard-question{min-height:220px}.step-meta{align-items:stretch;flex-direction:column}}\r\n#generateBtn{display:none}\r\n\n\n.banana-action{\n  border:0;\n  border-radius:14px;\n  padding:12px 18px;\n  background:linear-gradient(135deg,#ffd166,#ff8fab);\n  color:#34151f;\n  font-weight:900;\n  cursor:pointer;\n  box-shadow:0 12px 28px rgba(255,143,171,.28);\n}\n.banana-action:disabled{opacity:.62;cursor:not-allowed;box-shadow:none;}\n.banana-box{\n  margin-top:14px;\n  border:1px solid rgba(255,255,255,.14);\n  border-radius:18px;\n  padding:14px;\n  background:rgba(255,255,255,.06);\n}\n.banana-status{font-size:14px;color:var(--muted);line-height:1.7;white-space:pre-wrap;}\n.banana-preview{margin-top:12px;display:grid;gap:10px;}\n.banana-preview img{width:100%;border-radius:16px;border:1px solid rgba(255,255,255,.16);background:#fff;}\n.banana-preview a{color:var(--accent);word-break:break-all;font-weight:700;}\n\n.custom-field{margin-top:18px;padding:18px;border:1px solid rgba(143,211,255,.45);border-radius:18px;background:linear-gradient(135deg,rgba(143,211,255,.12),rgba(255,255,255,.05));box-shadow:0 12px 28px rgba(0,0,0,.18);}\r\n.custom-field-prominent{position:relative;}\r\n.custom-title{display:inline-flex;align-items:center;gap:6px;margin-bottom:10px;padding:5px 10px;border-radius:999px;background:rgba(143,211,255,.18);color:#dff4ff;font-weight:800;font-size:13px;}\r\n.custom-field input{width:100%;margin-top:6px;padding:14px 15px;border-radius:14px;border:1px solid rgba(143,211,255,.5);background:#11182b;color:var(--text);font:inherit;font-size:16px;}\r\n.custom-field input::placeholder{color:#8ea2c8;}\r\n.custom-field input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 4px rgba(143,211,255,.18);}\r\n.custom-note{margin:9px 0 0;color:#b9c8ea;font-size:12px;line-height:1.6;}\n\r\n\n/* 首页 / 问卷 / 结果页视图控制 */\nbody.is-home .grid{display:none;}\nbody.is-wizard .panel-title{display:none;}\nbody.is-wizard .shell{padding-top:12px;}\nbody.is-wizard .grid{margin-top:0;max-width:720px;}\nbody.is-wizard .form-panel{min-height:calc(100vh - 24px);padding:18px;}\nbody.is-wizard .wizard-question{min-height:auto;align-content:start;}\nbody.is-wizard .options{display:grid;grid-template-columns:1fr;gap:10px;}\nbody.is-wizard .option{width:100%;border-radius:16px;text-align:left;padding:14px 16px;}\nbody.is-wizard .question{padding:0;border:0;background:transparent;}\nbody.is-wizard .wizard-tip{margin-bottom:14px;}\nbody.is-result .hero{margin-bottom:22px;}\n\n@media(max-width:700px){\n  .shell{width:min(100% - 20px, 1260px);padding:12px 0 28px;}\n  .hero{padding:24px 20px;border-radius:24px;}\n  h1{font-size:clamp(32px,10vw,48px);line-height:1.08;}\n  .hero p{font-size:15px;line-height:1.7;}\n  body.is-wizard .shell{width:min(100% - 16px, 720px);padding-top:8px;}\n  body.is-wizard .form-panel{border-radius:22px;padding:14px;min-height:calc(100vh - 16px);}\n  body.is-wizard .step-meta{margin-bottom:12px;gap:8px;}\n  body.is-wizard .wizard-question h3{font-size:24px;margin-bottom:8px;}\n  body.is-wizard .wizard-tip{font-size:14px;line-height:1.55;margin-bottom:12px;}\n  body.is-wizard .option{font-size:15px;padding:13px 14px;}\n  body.is-wizard .wizard-nav{margin-top:14px;}\n}\r\n\n.banana-password-panel{display:grid;gap:12px;margin-bottom:14px;padding:14px;border:1px solid rgba(143,211,255,.34);border-radius:16px;background:rgba(143,211,255,.08);}\n.banana-password-panel[hidden]{display:none;}\n.banana-password-panel input{width:100%;margin-top:6px;padding:14px 15px;border-radius:14px;border:1px solid rgba(143,211,255,.5);background:#11182b;color:var(--text);font:inherit;font-size:16px;}\n.banana-password-panel input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 4px rgba(143,211,255,.18);}\n.banana-password-actions{display:flex;gap:10px;flex-wrap:wrap;}\n.banana-password-actions button{min-height:44px;}\n@media(max-width:700px){.banana-password-actions{display:grid;grid-template-columns:1fr;}.banana-password-actions button{width:100%;}}\r\n\n.manual-result-panel{margin-top:14px;padding:14px;border:1px solid rgba(143,211,255,.28);border-radius:18px;background:rgba(143,211,255,.07);}\n.manual-result-title{font-weight:900;color:#dff4ff;margin-bottom:10px;font-size:14px;}\n.manual-result-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;}\n.manual-result-grid label{display:grid;gap:6px;color:var(--muted);font-size:13px;font-weight:800;}\n.manual-result-grid input{width:100%;padding:11px 12px;border-radius:13px;border:1px solid rgba(143,211,255,.42);background:#11182b;color:var(--text);font:inherit;font-size:16px;}\n.manual-result-grid input:focus{outline:none;border-color:var(--accent);box-shadow:0 0 0 4px rgba(143,211,255,.16);}\n.manual-result-actions{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;margin-top:10px;}\n.manual-result-actions button{width:100%;}\n@media(max-width:900px){.manual-result-grid,.manual-result-actions{grid-template-columns:repeat(2,minmax(0,1fr));}}\n@media(max-width:560px){.manual-result-grid,.manual-result-actions{grid-template-columns:1fr;}}\r\n\r\n.version-row{margin-top:14px;color:var(--muted);font-size:12px;text-align:right;opacity:.86;}\r\n.version-row span{color:#dff4ff;font-weight:800;}\r\n@media(max-width:700px){.version-row{text-align:center;}.hero-actions #refreshLatestBtn{width:100%;}}\r\n\r\n\n.advanced-note{margin:0 0 14px;color:var(--muted);font-size:13px;line-height:1.7;}\nbody.is-wizard .advanced{margin-top:16px;}\nbody.is-result .result-panel{display:block;}\n\n\n.gpt-action{\n  border:0;\n  border-radius:14px;\n  padding:12px 18px;\n  background:linear-gradient(135deg,#b8f7d4,#8fd3ff);\n  color:#081b1f;\n  font-weight:900;\n  cursor:pointer;\n  box-shadow:0 12px 28px rgba(143,211,255,.24);\n}\n.gpt-action:disabled{opacity:.62;cursor:not-allowed;box-shadow:none;}\n";
