﻿const BANANA_SUBMIT_URL = 'https://nanobananapro.cloud/api/v1/image/nano-banana';
const BANANA_RESULT_URL = 'https://nanobananapro.cloud/api/v1/image/nano-banana/result';
const GPT_IMAGE2_SUBMIT_URL = 'https://api.wuyinkeji.com/api/async/image_gpt';
const GPT_IMAGE2_DETAIL_URL = 'https://api.wuyinkeji.com/api/async/detail';
const ACCESS_PASSWORD = 'jibao';
const DEFAULT_REFERENCE_IMAGE_URL = 'https://sewindwolf.art/furry-creator/assets/blank-reference.png';

function json(data, status = 200){
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json; charset=utf-8',
      'Cache-Control': 'no-store'
    }
  });
}

function extractTaskId(data){
  return data?.data?.id || data?.data?.taskId || data?.taskId || data?.id || '';
}

function extractImageUrl(data){
  return data?.data?.results?.[0]?.url || data?.data?.url || data?.data?.imageUrl || data?.result?.url || data?.url || '';
}

function extractImageUrlDeep(value){
  if(!value) return '';
  if(typeof value === 'string'){
    if(/^https?:\/\//i.test(value)) return value;
    try { return extractImageUrlDeep(JSON.parse(value)); } catch { return ''; }
  }
  if(Array.isArray(value)){
    for(const item of value){
      const found = extractImageUrlDeep(item);
      if(found) return found;
    }
    return '';
  }
  if(typeof value === 'object'){
    for(const key of ['url','image_url','imageUrl','src','data','result','urls']){
      const found = extractImageUrlDeep(value[key]);
      if(found) return found;
    }
  }
  return '';
}

function extractGptImage2Url(data){
  return extractImageUrlDeep(data?.data?.result || data?.result || data?.data);
}

function formEncode(fields){
  return fields.map(([key, value]) => encodeURIComponent(key) + '=' + encodeURIComponent(value)).join('&');
}

async function sleep(ms){ return new Promise(resolve => setTimeout(resolve, ms)); }

async function submitBanana(prompt, BANANA_KEY){
  const form = new FormData();
  form.append('prompt', prompt);
  form.append('model', 'nano-banana-pro');
  form.append('mode', 'image-to-image');
  form.append('aspectRatio', '16:9');
  form.append('width', '1920');
  form.append('height', '1080');
  form.append('imageSize', '1K');
  form.append('imageUrl', DEFAULT_REFERENCE_IMAGE_URL);
  const resp = await fetch(BANANA_SUBMIT_URL, {
    method: 'POST',
    headers: { Authorization: `Bearer ${BANANA_KEY}` },
    body: form
  });
  const text = await resp.text();
  let data;
  try { data = JSON.parse(text); } catch { data = { raw: text }; }
  if(!resp.ok) throw new Error(`submit ${resp.status}: ${text.slice(0, 500)}`);
  if(data?.code === 401 || data?.message === 'Unauthorized') throw new Error('Banana 官方鉴权失败：服务端 API Key 未被官方接口接受');
  const taskId = extractTaskId(data);
  if(!taskId) throw new Error(`no taskId: ${text.slice(0, 500)}`);
  return taskId;
}

async function pollBanana(taskId, BANANA_KEY){
  for(let i = 0; i < 36; i++){
    await sleep(5000);
    const resp = await fetch(BANANA_RESULT_URL, {
      method: 'POST',
      headers: { Authorization: `Bearer ${BANANA_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ taskId })
    });
    const text = await resp.text();
    let data;
    try { data = JSON.parse(text); } catch { data = { raw: text }; }
    if(!resp.ok) continue;
    const status = data?.data?.status || data?.status;
    const imageUrl = extractImageUrl(data);
    if(['succeeded','success','completed'].includes(status) && imageUrl) return imageUrl;
    if(['failed','error'].includes(status)) throw new Error(`task failed: ${text.slice(0, 500)}`);
  }
  throw new Error('生成超时，请稍后重试');
}

async function submitGptImage2(prompt, GPT_IMAGE2_KEY){
  const body = formEncode([
    ['key', GPT_IMAGE2_KEY],
    ['prompt', prompt],
    ['urls[]', DEFAULT_REFERENCE_IMAGE_URL],
    ['size', '1792x1024']
  ]);
  const resp = await fetch(GPT_IMAGE2_SUBMIT_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body
  });
  const text = await resp.text();
  let data;
  try { data = JSON.parse(text); } catch { data = { raw: text }; }
  if(!resp.ok) throw new Error(`GPT submit ${resp.status}: ${text.slice(0, 500)}`);
  if(data?.code !== 200) throw new Error(`GPT submit failed: ${text.slice(0, 500)}`);
  const taskId = data?.data?.id || data?.data?.taskId || data?.id || '';
  if(!taskId) throw new Error(`GPT no taskId: ${text.slice(0, 500)}`);
  return taskId;
}

async function pollGptImage2(taskId, GPT_IMAGE2_KEY){
  const detailUrl = GPT_IMAGE2_DETAIL_URL + '?key=' + encodeURIComponent(GPT_IMAGE2_KEY) + '&id=' + encodeURIComponent(taskId);
  for(let i = 0; i < 72; i++){
    await sleep(5000);
    const resp = await fetch(detailUrl);
    const text = await resp.text();
    let data;
    try { data = JSON.parse(text); } catch { data = { raw: text }; }
    if(!resp.ok) continue;
    const d = data?.data || {};
    const status = d.status;
    const imageUrl = extractGptImage2Url(data);
    if(imageUrl && status !== 0) return imageUrl;
    if(status === 2 && imageUrl) return imageUrl;
    if(status === 3) throw new Error(`GPT task failed: ${text.slice(0, 500)}`);
  }
  throw new Error('GPT 生成超时，请稍后重试');
}

async function handleBananaGenerate(request, env){
  if(request.method !== 'POST') return json({ ok:false, error:'method not allowed' }, 405);
  let body;
  try { body = await request.json(); } catch { return json({ ok:false, error:'请求体不是有效 JSON' }, 400); }
  if(body.password !== ACCESS_PASSWORD) return json({ ok:false, error:'密码错误' }, 403);
  const prompt = String(body.prompt || '').trim();
  if(!prompt) return json({ ok:false, error:'缺少 prompt' }, 400);
  if(prompt.length > 6000) return json({ ok:false, error:'prompt 过长，请精简后再试' }, 400);
  const finalPrompt = prompt + '\n\nIMPORTANT: 16:9 wide horizontal landscape canvas, single complete character reference sheet image arranged left-to-right, no text labels, no watermark, fully clothed, no nudity.';
  const BANANA_KEY = String(env.BANANA_KEY || '').trim();
  if(!BANANA_KEY) throw new Error('服务端未配置 Banana Key');
  const taskId = await submitBanana(finalPrompt, BANANA_KEY);
  const imageUrl = await pollBanana(taskId, BANANA_KEY);
  return json({ ok:true, taskId, imageUrl });
}

async function handleGptGenerate(request, env){
  if(request.method !== 'POST') return json({ ok:false, error:'method not allowed' }, 405);
  let body;
  try { body = await request.json(); } catch { return json({ ok:false, error:'请求体不是有效 JSON' }, 400); }
  if(body.password !== ACCESS_PASSWORD) return json({ ok:false, error:'密码错误' }, 403);
  const prompt = String(body.prompt || '').trim();
  if(!prompt) return json({ ok:false, error:'缺少 prompt' }, 400);
  if(prompt.length > 6000) return json({ ok:false, error:'prompt 过长，请精简后再试' }, 400);
  const finalPrompt = prompt + '\n\nIMPORTANT: 16:9 wide horizontal landscape canvas, single complete character reference sheet image arranged left-to-right, no text labels, no watermark, fully clothed, no nudity.';
  const GPT_IMAGE2_KEY = String(env.GPT_IMAGE2_KEY || '').trim();
  if(!GPT_IMAGE2_KEY) throw new Error('服务端未配置 GPT-Image-2 Key');
  const taskId = await submitGptImage2(finalPrompt, GPT_IMAGE2_KEY);
  const imageUrl = await pollGptImage2(taskId, GPT_IMAGE2_KEY);
  return json({ ok:true, taskId, imageUrl });
}

export default {
  async fetch(request, env, ctx){
    const url = new URL(request.url);
    try{
      if(url.pathname === '/api/banana-generate') return await handleBananaGenerate(request, env);
      if(url.pathname === '/api/gpt-generate') return await handleGptGenerate(request, env);
      const furryAsset = handleFurryCreatorAsset(url.pathname);
      if(furryAsset) return furryAsset;
      return env.ASSETS.fetch(request);
    }catch(err){
      return json({ ok:false, error: err?.message || String(err) }, 500);
    }
  }
};




